FILES = {"header.py": "from PySide6.QtWidgets import QLabel\nfrom PySide6.QtCore import Qt\n\nclass PageHeader(QLabel):\n    def __init__(self, text):\n        super().__init__(text)\n        self.setAlignment(Qt.AlignCenter)\n        self.setFixedHeight(45)\n        self.setStyleSheet(\"\"\"\n            background:#2F80ED;\n            color:white;\n            font-size:20px;\n            font-weight:bold;\n            padding:8px;\n        \"\"\")", "heads.py": "from ui2.common_table import style_table\nfrom PySide6.QtWidgets import *\nfrom database import Database\nfrom ui2.header import PageHeader\nfrom PySide6.QtCore import Qt, Signal\n\nclass HeadPage(QWidget):\n    head_added = Signal()\n    subhead_added = Signal()  # \ud83d\udd25 ADD THIS\n    def __init__(self):\n        super().__init__()\n\n        self.db = Database()\n\n        layout = QVBoxLayout(self)\n        layout.addWidget(PageHeader(\"Manage Heads\"))\n\n        # ================= ADD HEAD =================\n        head_group = QGroupBox(\"Add Head\")\n        head_layout = QFormLayout()\n\n        self.head_type = QComboBox()\n        self.head_type.addItems([\"Income\", \"Expense\"])\n\n        self.head_name = QLineEdit()\n\n        self.btn_add_head = QPushButton(\"Add Head\")\n\n        head_layout.addRow(\"Type\", self.head_type)\n        head_layout.addRow(\"Head Name\", self.head_name)\n        head_layout.addRow(self.btn_add_head)\n\n        head_group.setLayout(head_layout)\n        layout.addWidget(head_group)\n\n        # ================= ADD SUBHEAD =================\n        sub_group = QGroupBox(\"Add Subhead\")\n        sub_layout = QFormLayout()\n\n        self.sub_type = QComboBox()\n        self.sub_type.addItems([\"Income\", \"Expense\"])\n\n        self.sub_head_combo = QComboBox()\n\n        self.sub_name = QLineEdit()\n\n        self.btn_add_sub = QPushButton(\"Add Subhead\")\n\n        sub_layout.addRow(\"Type\", self.sub_type)\n        sub_layout.addRow(\"Head\", self.sub_head_combo)\n        sub_layout.addRow(\"Subhead\", self.sub_name)\n        sub_layout.addRow(self.btn_add_sub)\n\n        sub_group.setLayout(sub_layout)\n        layout.addWidget(sub_group)\n\n        # ================= TABLE =================\n        self.table = QTableWidget()\n        self.table.setAlternatingRowColors(True)\n\n        headers = [\"Head ID\", \"Type\", \"Head Name\"]\n\n        self.table.setColumnCount(len(headers))\n        self.table.setHorizontalHeaderLabels(headers)\n        self.table.verticalHeader().setVisible(False)\n        self.table.horizontalHeader().setStretchLastSection(True)\n\n        layout.addWidget(self.table)\n\n        # ================= CONNECT =================\n        self.sub_type.currentTextChanged.connect(self.load_heads_for_sub)\n        self.btn_add_head.clicked.connect(self.add_head_master)\n        self.btn_add_sub.clicked.connect(self.add_sub_master)\n\n        # ================= LOAD =================\n        self.load_heads_for_sub()\n        self.refresh()\n\n    # ================= LOAD HEADS =================\n    def load_heads_for_sub(self):\n\n        self.sub_head_combo.clear()\n\n        rows = self.db.conn.execute(\n            \"SELECT name FROM heads WHERE type=?\",\n            (self.sub_type.currentText(),)\n        ).fetchall()\n\n        for r in rows:\n            self.sub_head_combo.addItem(r[0])\n\n    # ================= ADD HEAD =================\n    def add_head_master(self):\n\n        typ = self.head_type.currentText()\n        head = self.head_name.text().strip()\n\n        if not head:\n            QMessageBox.warning(self, \"Error\", \"Enter Head\")\n            return\n\n        exists = self.db.conn.execute(\n            \"SELECT id FROM heads WHERE type=? AND name=?\",\n            (typ, head)\n        ).fetchone()\n\n        if not exists:\n            self.db.add_head(typ, head)\n            self.head_added.emit()\n            self.parent().voucher_page.load_heads()\n            QMessageBox.information(self, \"Saved\", \"Head Added\")\n\n        self.head_name.clear()\n        self.load_heads_for_sub()\n        self.refresh()\n\n    # ================= ADD SUBHEAD =================\n    def add_sub_master(self):\n\n        typ = self.sub_type.currentText()\n        head = self.sub_head_combo.currentText()\n        sub = self.sub_name.text().strip()\n\n        if not sub:\n            QMessageBox.warning(self, \"Error\", \"Enter Subhead\")\n            return\n\n        self.db.add_subhead(typ, head, sub)\n        self.subhead_added.emit()\n        self.parent().voucher_page.load_heads()\n        QMessageBox.information(self, \"Saved\", \"Subhead Added\")\n\n        self.sub_name.clear()\n\n    # ================= REFRESH =================\n    def refresh(self):\n\n        rows = self.db.conn.execute(\"SELECT * FROM heads\").fetchall()\n\n        if not rows:\n            self.table.setRowCount(0)\n            return\n\n        self.table.setRowCount(len(rows))\n\n        for r, row in enumerate(rows):\n            for c, val in enumerate(row):\n                self.table.setItem(r, c, QTableWidgetItem(str(val)))\n\n        self.table.resizeColumnsToContents()\n        style_table(self.table)\n        style_table(self.table)", "mainwindow.py": "from PySide6.QtWidgets import *\nfrom PySide6.QtGui import QIcon, QAction, QFont, QPixmap\nfrom PySide6.QtCore import QSize, Qt\n\nfrom ui2.student_page import StudentPage\nfrom ui2.vouchers import VoucherPage\nfrom ui2.heads import HeadPage\nfrom ui2.reports import ReportPage\nfrom PySide6.QtCore import Signal\n\n# -------------------------------------------------\n# OPTIONAL PyQt6 imports (SAFE \u2013 will NOT crash)\n# -------------------------------------------------\ntry:\n    from PyQt6.QtCore import Qt as Qt6\n    from PyQt6.QtWidgets import QLabel as QLabel6, QVBoxLayout as QVBoxLayout6, QWidget as QWidget6\n    from PyQt6.QtGui import QFont as QFont6\nexcept ModuleNotFoundError:\n    Qt6 = QLabel6 = QVBoxLayout6 = QWidget6 = QFont6 = None\n\n\nclass MainWindow(QMainWindow):\n\n    def __init__(self):\n        super().__init__()\n        self.setWindowTitle(\"Darus\")\n        self.resize(1400, 850)\n\n        # =================================================\n        # CENTRAL ROOT (ONLY ONCE)\n        # =================================================\n        central = QWidget()\n        self.setCentralWidget(central)\n\n        main_layout = QVBoxLayout(central)\n        main_layout.setContentsMargins(0, 0, 0, 0)\n        # ================= HEADER IMAGE =================\n        header = QLabel()\n\n        pix = QPixmap(\"icons/header.png\")\n\n        header.setPixmap(\n            pix.scaled(1200, 140, Qt.KeepAspectRatio, Qt.SmoothTransformation)\n        )\n\n        header.setAlignment(Qt.AlignCenter)\n\n        main_layout.addWidget(header)\n        # =================================================\n        # GLOBAL STYLES\n        # =================================================\n        self.setStyleSheet(\"\"\"\n        * {\n            font-family: Segoe UI, Arial;\n            font-size: 13px;\n        }\n\n        QMainWindow {\n            background: #F8FAFC;\n        }\n\n        QPushButton {\n            background: #36ABD6;\n            color: white;\n            border-radius: 6px;\n            padding: 6px 10px;\n            font-weight: bold;\n        }\n\n        QPushButton:hover {\n            background: #1D4ED8;\n        }\n\n        QWidget#sidebar {\n            background: #EEF2FF;\n            border-right: 1px solid #e5e7eb;\n        }\n        \"\"\")\n\n        # =================================================\n        # BODY\n        # =================================================\n        body_layout = QHBoxLayout()\n        body_layout.setSpacing(0)\n        main_layout.addLayout(body_layout)\n\n        # =================================================\n        # STACKED PAGES\n        # =================================================\n        self.stack = QStackedWidget()\n\n        self.student_page = StudentPage()\n        self.voucher_page = VoucherPage()\n        self.head_page = HeadPage()\n        self.report_page = ReportPage()\n\n        self.stack.addWidget(self.student_page)\n        self.stack.addWidget(self.voucher_page)\n        self.stack.addWidget(self.head_page)\n        self.stack.addWidget(self.report_page)\n        self.student_page.student_added.connect(self.voucher_page.load_students)\n        self.student_page.student_added.connect(self.report_page.refresh_students)\n        self.head_page.head_added.connect(self.voucher_page.load_heads)\n        self.head_page.subhead_added.connect(lambda: (self.voucher_page.load_heads(),self.voucher_page.load_subheads()))\n        # =================================================\n        # SIDEBAR\n        # =================================================\n        sidebar_layout = QVBoxLayout()\n        sidebar_layout.setContentsMargins(10, 10, 10, 10)\n        sidebar_layout.setSpacing(6)\n\n        def style_button(btn):\n            btn.setIconSize(QSize(22, 22))\n            btn.setFixedHeight(48)\n            btn.setCursor(Qt.PointingHandCursor)\n\n        self.btn_students = QPushButton(\" Students  \u25be\")\n        self.btn_students.setIcon(QIcon(\"icons/student.png\"))\n        self.btn_students.setCheckable(True)\n\n        self.student_submenu = QWidget()\n        submenu_layout = QVBoxLayout(self.student_submenu)\n        submenu_layout.setContentsMargins(30, 0, 0, 0)\n\n        self.btn_registration = QPushButton(\"Registration\")\n        self.btn_student_list = QPushButton(\"Student List\")\n\n        submenu_layout.addWidget(self.btn_registration)\n        submenu_layout.addWidget(self.btn_student_list)\n        self.student_submenu.setFixedHeight(0)\n\n        def toggle_students():\n            if self.student_submenu.height() == 0:\n                self.student_submenu.setFixedHeight(70)\n                self.btn_students.setText(\" Students  \u25b4\")\n            else:\n                self.student_submenu.setFixedHeight(0)\n                self.btn_students.setText(\" Students  \u25be\")\n\n        self.btn_students.clicked.connect(toggle_students)\n\n        sidebar_layout.addWidget(self.btn_students)\n        sidebar_layout.addWidget(self.student_submenu)\n\n        btn_voucher = QPushButton(\" Vouchers\")\n        btn_voucher.setIcon(QIcon(\"icons/voucher.png\"))\n\n        btn_heads = QPushButton(\" Heads\")\n        btn_heads.setIcon(QIcon(\"icons/heads.png\"))\n\n        btn_report = QPushButton(\" Reports\")\n        btn_report.setIcon(QIcon(\"icons/reports.png\"))\n\n        btn_exit = QPushButton(\" Exit\")\n        btn_exit.setIcon(QIcon(\"icons/exit.png\"))\n\n        for b in [self.btn_students, btn_voucher, btn_heads, btn_report, btn_exit]:\n            style_button(b)\n            sidebar_layout.addWidget(b)\n\n        sidebar_layout.addStretch()\n\n        side = QWidget(objectName=\"sidebar\")\n        side.setFixedWidth(190)\n        side.setLayout(sidebar_layout)\n\n        body_layout.addWidget(side)\n        body_layout.addWidget(self.stack, 1)\n\n        # =================================================\n        # CONNECTIONS\n        # =================================================\n        self.btn_registration.clicked.connect(\n            lambda: (\n                self.stack.setCurrentWidget(self.student_page),\n                self.student_page.show_registration()\n            )\n        )\n\n        self.btn_student_list.clicked.connect(\n            lambda: (\n                self.stack.setCurrentWidget(self.student_page),\n                self.student_page.show_list()\n            )\n        )\n\n        btn_voucher.clicked.connect(lambda: self.stack.setCurrentWidget(self.voucher_page))\n        btn_heads.clicked.connect(lambda: self.stack.setCurrentWidget(self.head_page))\n        btn_report.clicked.connect(lambda: self.stack.setCurrentWidget(self.report_page))\n        btn_exit.clicked.connect(self.close)", "reports.py": "from ui2.common_table import style_table\nfrom PySide6.QtWidgets import *\nfrom PySide6.QtCore import QDate\nfrom database import Database\nfrom ui2.header import PageHeader\nfrom reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle\nfrom reportlab.lib import colors\nfrom reportlab.lib.styles import getSampleStyleSheet\nfrom datetime import datetime\nimport os\n\n\n\n\n# =====================================================\n# MAIN REPORT PAGE (TABS)\n# =====================================================\nclass ReportPage(QWidget):\n   def __init__(self):\n       super().__init__()\n\n\n       layout = QVBoxLayout(self)\n       layout.addWidget(PageHeader(\"Reports\"))\n\n       tabs = QTabWidget()\n\n       self.finance_page = FinancePage()\n       self.fee_page = FeePage()\n       self.defaulter_page = DefaulterPage()\n       self.collection_page = CollectionPage()\n       self.sms_page = SmsListPage()  # \ud83d\udd25 ONLY ONE SMS TAB\n\n       tabs.addTab(self.finance_page, \"Finance\")\n       tabs.addTab(self.fee_page, \"Fees\")\n       tabs.addTab(self.defaulter_page, \"Defaulters\")\n       tabs.addTab(self.collection_page, \"Collection\")\n       tabs.addTab(self.sms_page, \"SMS List\")   # \u2705 use object\n       layout.addWidget(tabs)\n\n   def refresh_students(self):\n\n       self.fee_page.load_report()\n       self.defaulter_page.load_data()\n       self.sms_list_page.load_data()\n       self.sms_reminder_page.load_data()\n# =================================================\n# SEARCH FILTER\n# =================================================\n   def filter_table(self, text):\n       text = text.lower()\n\n\n       for row in range(self.table.rowCount()):\n           match = False\n           for col in range(self.table.columnCount()):\n               item = self.table.item(row, col)\n               if item and text in item.text().lower():\n                   match = True\n                   break\n\n\n           self.table.setRowHidden(row, not match)\n\n\n\n\n# =====================================================\n# FINANCE REPORT TAB\n# =====================================================\nclass FinancePage(QWidget):\n   def __init__(self):\n       super().__init__()\n\n\n       self.db = Database()\n\n\n       layout = QVBoxLayout(self)\n       layout.setSpacing(12)\n\n\n       # =================================================\n       # FILTER BAR\n       # =================================================\n       top = QHBoxLayout()\n\n\n       self.from_date = QDateEdit(calendarPopup=True)\n       self.to_date = QDateEdit(calendarPopup=True)\n\n\n       self.from_date.setDate(QDate.currentDate().addMonths(-1))\n       self.to_date.setDate(QDate.currentDate())\n\n\n       self.type_combo = QComboBox()\n       self.type_combo.addItems([\"All\", \"Income\", \"Expense\"])\n\n\n       self.btn_receipt = QPushButton(\"\ud83e\uddfe Receipt\")\n       btn_load = QPushButton(\"\ud83d\udd0d Load Report\")\n       btn_load.setMinimumHeight(34)\n       btn_load.clicked.connect(self.load_report)\n\n\n       top.addWidget(QLabel(\"From\"))\n       top.addWidget(self.from_date)\n\n\n       top.addWidget(QLabel(\"To\"))\n       top.addWidget(self.to_date)\n\n\n       top.addWidget(QLabel(\"Type\"))\n       top.addWidget(self.type_combo)\n\n\n       top.addWidget(btn_load)\n       top.addStretch()\n\n\n       layout.addLayout(top)\n\n\n       # =================================================\n       # SUMMARY\n       # =================================================\n       self.summary = QLabel(\"\")\n       self.summary.setStyleSheet(\"\"\"\n           font-weight:bold;\n           font-size:15px;\n           padding:10px;\n           background:#F4F6F8;\n           border-radius:6px;\n       \"\"\")\n       layout.addWidget(self.summary)\n\n\n       # =================================================\n       # TABLE\n       # =================================================\n       self.table = QTableWidget()\n       self.table.setAlternatingRowColors(True)\n       self.table.setEditTriggers(QTableWidget.NoEditTriggers)\n       self.table.setSelectionBehavior(QTableWidget.SelectRows)\n\n\n       layout.addWidget(self.table,1)\n\n\n       layout.addStretch()\n\n\n       self.load_report()\n\n   def style_report_table(self, table):\n       from PySide6.QtWidgets import QHeaderView, QSizePolicy, QAbstractItemView\n\n       table.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)\n\n       header = table.horizontalHeader()\n\n       # Prevent overlapping\n       header.setSectionResizeMode(QHeaderView.Stretch)\n\n       table.verticalHeader().setVisible(False)\n       table.verticalHeader().setDefaultSectionSize(28)\n\n       table.setAlternatingRowColors(True)\n       table.setWordWrap(True)\n       table.setSortingEnabled(True)\n\n       # \u2705 Correct fix\n       table.setEditTriggers(QAbstractItemView.NoEditTriggers)\n\n       header.setMinimumHeight(35)\n   # =================================================\n   # LOAD REPORT\n   # =================================================\n   def load_report(self):\n       rows = self.db.get_vouchers()\n\n\n       from_d = self.from_date.date()\n       to_d = self.to_date.date()\n       typ = self.type_combo.currentText()\n\n\n       filtered = []\n\n\n       income = expense = cash = bank = 0\n\n\n       for r in rows:\n           (\n               vid, date_str, vtype, head, sub,\n               student, cls, amount, mode, note\n           ) = r\n\n\n           # convert string \u2192 QDate\n           date = QDate.fromString(date_str, \"yyyy-MM-dd\")\n\n\n           if not date.isValid():\n               continue\n\n\n           # date filter\n           if not (from_d <= date <= to_d):\n               continue\n\n\n           # type filter\n           if typ != \"All\" and vtype != typ:\n               continue\n\n\n           filtered.append(r)\n\n\n           # ---------------- calculations ----------------\n           if vtype == \"Income\":\n               income += amount\n               if mode.lower() == \"cash\":\n                   cash += amount\n               else:\n                   bank += amount\n           else:\n               expense += amount\n               if mode.lower() == \"cash\":\n                   cash -= amount\n               else:\n                   bank -= amount\n\n\n       net = income - expense\n\n\n       # =================================================\n       # SUMMARY TEXT (\u20b9 formatted)\n       # =================================================\n       self.summary.setText(\n           f\"Income: \u20b9{int(income):,}     \"\n           f\"Expense: \u20b9{int(expense):,}     \"\n           f\"Cash: \u20b9{int(cash):,}     \"\n           f\"Bank: \u20b9{int(bank):,}     \"\n           f\"Net: \u20b9{int(net):,}\"\n       )\n\n\n       # =================================================\n       # TABLE DATA\n       # =================================================\n       headers = [\n           \"ID\", \"Date\", \"Type\", \"Head\", \"Subhead\",\n           \"Student\", \"Class\", \"Amount\", \"Mode\", \"Note\"\n       ]\n\n\n       self.table.setRowCount(len(filtered))\n       self.table.setColumnCount(len(headers))\n       self.table.setHorizontalHeaderLabels(headers)\n\n\n       for r, row in enumerate(filtered):\n           for c, val in enumerate(row):\n\n\n               # money formatting only for Amount column\n               if c == 7:\n                   text = f\"\u20b9{int(val):,}\"\n               else:\n                   text = str(val)\n\n\n               self.table.setItem(r, c, QTableWidgetItem(text))\n\n\n       # self.table.resizeColumnsToContents()\n        style_table(self.table)-------1\n       style_table(self.table)\n\n# =====================================================\n# FEE REPORT TAB\n# =====================================================\nclass FeePage(QWidget):\n   def __init__(self):\n       super().__init__()\n\n\n       self.db = Database()\n\n\n       layout = QVBoxLayout(self)\n\n\n       # ---------- Filters ----------\n       top = QHBoxLayout()\n\n\n       self.class_combo = QComboBox()\n       self.class_combo.addItems([\"All\",\"6th\",\"7th\",\"8th\",\"9th\",\"10th\"])\n\n\n       btn = QPushButton(\"Load\")\n       btn.clicked.connect(self.load_report)\n\n\n       top.addWidget(QLabel(\"Select Class\"))\n       top.addWidget(self.class_combo)\n       top.addWidget(btn)\n\n\n       layout.addLayout(top)\n\n\n       # ---------- Summary ----------\n       self.summary = QLabel(\"\")\n       self.summary.setStyleSheet(\"font-weight:bold;padding:8px;\")\n       layout.addWidget(self.summary)\n\n\n       # ---------- Table ----------\n       self.table = QTableWidget()\n       self.table.setAlternatingRowColors(True)\n\n\n       layout.addWidget(self.table)\n       self.load_report()\n\n   def style_report_table(self, table):\n       from PySide6.QtWidgets import QHeaderView, QSizePolicy, QAbstractItemView\n\n       table.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)\n\n       header = table.horizontalHeader()\n\n       # Prevent overlapping\n       header.setSectionResizeMode(QHeaderView.Stretch)\n\n       table.verticalHeader().setVisible(False)\n       table.verticalHeader().setDefaultSectionSize(28)\n\n       table.setAlternatingRowColors(True)\n       table.setWordWrap(True)\n       table.setSortingEnabled(True)\n\n       # \u2705 Correct fix\n       table.setEditTriggers(QAbstractItemView.NoEditTriggers)\n\n       header.setMinimumHeight(35)\n   def load_report(self):\n       students = self.db.get_students()\n       vouchers = self.db.get_vouchers()\n\n\n       selected_class = self.class_combo.currentText()\n\n\n       rows = []\n\n\n       total_annual = total_paid = total_pending = 0\n       total_pending_months = 0\n\n\n       for s in students:\n           student_id = s[1]\n           name = s[2]\n           cls = s[7]\n           annual = float(s[13] or 0)\n\n\n           if selected_class != \"All\" and cls != selected_class:\n               continue\n\n\n           monthly = annual / 12 if annual else 0\n\n\n           # ---------------- PAID CALC ----------------\n           paid = 0\n           for v in vouchers:\n               if v[3].lower() == \"fees\" and v[5] == name:\n                   paid += float(v[7])\n\n\n           pending = annual - paid\n\n\n           # ---------------- MONTH CALC ----------------\n           paid_months = int(paid / monthly) if monthly else 0\n           pending_months = 12 - paid_months\n\n\n           # ---------------- TOTALS ----------------\n           total_annual += annual\n           total_paid += paid\n           total_pending += pending\n           total_pending_months += pending_months\n\n\n           rows.append((\n               student_id,\n               name,\n               cls,\n               int(annual),\n               int(monthly),\n               int(paid),\n               int(pending),\n               pending_months\n           ))\n\n\n       # ================= SUMMARY =================\n       self.summary.setText(\n           f\"Annual: \u20b9{int(total_annual):,}    \"\n           f\"Paid: \u20b9{int(total_paid):,}    \"\n           f\"Pending \u20b9: \u20b9{int(total_pending):,}    \"\n           f\"Pending Months: {total_pending_months}\"\n       )\n\n\n       # ================= TABLE =================\n       headers = [\n           \"Student ID\",\n           \"Name\",\n           \"Class\",\n           \"Annual Fee\",\n           \"Monthly Fee\",\n           \"Paid\",\n           \"Pending \u20b9\",\n           \"Pending Months\"\n       ]\n\n\n       self.table.setRowCount(len(rows))\n       self.table.setColumnCount(len(headers))\n       self.table.setHorizontalHeaderLabels(headers)\n\n\n       for r, row in enumerate(rows):\n           for c, val in enumerate(row):\n\n\n               # money formatting\n               if isinstance(val, int) and c in [3, 4, 5, 6]:\n                   text = f\"\u20b9{val:,}\"\n               else:\n                   text = str(val)\n\n\n               self.table.setItem(r, c, QTableWidgetItem(text))\n\n\n       # self.table.resizeColumnsToContents()\n        style_table(self.table)-------------2\n\n       style_table(self.table)\n\n\n\n   # =================================================\n   # STUDENT FEE HISTORY\n   # =================================================\n   def show_history(self):\n\n\n       name = self.name.text().strip()\n\n\n       if not name:\n           QMessageBox.warning(self, \"Error\", \"Select student first\")\n           return\n\n\n       rows = self.db.get_vouchers()\n\n\n       # -------- filter only this student's fee payments\n       data = [\n           r for r in rows\n           if r[3].lower() == \"fees\" and r[5] == name\n       ]\n\n\n       if not data:\n           QMessageBox.information(self, \"Info\", \"No fee records found\")\n           return\n\n\n       # -------- sort by date\n       data.sort(key=lambda x: x[1])\n\n\n       # =================================================\n       # Dialog\n       # =================================================\n       dlg = QDialog(self)\n       dlg.setWindowTitle(f\"Fee History - {name}\")\n       dlg.resize(750, 450)\n\n\n       layout = QVBoxLayout(dlg)\n\n\n       table = QTableWidget()\n       layout.addWidget(table)\n\n\n       # -------- custom headers (clean names)\n       headers = [\n           \"ID\",\n           \"Date\",\n           \"Type\",\n           \"Head\",\n           \"Subhead\",\n           \"Student\",\n           \"Class\",\n           \"Amount\",\n           \"Mode\",\n           \"Note\"\n       ]\n\n\n       table.setRowCount(len(data))\n       table.setColumnCount(len(headers))\n       table.setHorizontalHeaderLabels(headers)\n\n\n       # -------- fill table\n       for r, row in enumerate(data):\n           for c, val in enumerate(row):\n\n\n               # \u2b50 format money column\n               if c == 7:\n                   text = f\"\u20b9{int(val):,}\"\n               else:\n                   text = str(val)\n\n\n               table.setItem(r, c, QTableWidgetItem(text))\n\n\n       # table.resizeColumnsToContents()\n       style_table(table)\n\n       dlg.exec()\n# =====================================================\n# SMS REMINDER PAGE\n# =====================================================\nclass SmsListPage(QWidget):\n   def __init__(self):\n       super().__init__()\n\n\n       self.db = Database()\n\n\n       layout = QVBoxLayout(self)\n\n\n       title = QLabel(\"SMS Reminder List (Fee Pending)\")\n       title.setStyleSheet(\"font-weight:bold;font-size:16px;padding:6px;\")\n       layout.addWidget(title)\n\n\n       # -------- table --------\n       self.table = QTableWidget()\n       layout.addWidget(self.table)\n\n\n       btn_export = QPushButton(\"Export Excel\")\n       btn_export.clicked.connect(self.export_excel)\n       layout.addWidget(btn_export)\n\n\n       self.load_data()\n\n   def style_report_table(self, table):\n       from PySide6.QtWidgets import QHeaderView, QSizePolicy, QAbstractItemView\n\n       table.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)\n\n       header = table.horizontalHeader()\n\n       # Prevent overlapping\n       header.setSectionResizeMode(QHeaderView.Stretch)\n\n       table.verticalHeader().setVisible(False)\n       table.verticalHeader().setDefaultSectionSize(28)\n\n       table.setAlternatingRowColors(True)\n       table.setWordWrap(True)\n       table.setSortingEnabled(True)\n\n       # \u2705 Correct fix\n       table.setEditTriggers(QAbstractItemView.NoEditTriggers)\n\n       header.setMinimumHeight(35)\n\n   # -------------------------------------------------\n   def load_data(self):\n       students = self.db.get_students()\n       vouchers = self.db.get_vouchers()\n\n\n       rows = []\n\n\n       for s in students:\n           student_id = s[1]\n           name = s[2]\n           cls = s[7]\n           phone = s[8]\n           annual = float(s[13] or 0)\n\n\n           monthly = annual / 12 if annual else 0\n\n\n           paid = 0\n\n\n           # calculate paid fees\n           for v in vouchers:\n               if v[3].lower() == \"fees\" and v[5] == name:\n                   paid += float(v[7] or 0)\n\n\n           if monthly == 0:\n               continue\n\n\n           months_paid = int(paid / monthly)\n           pending_months = 12 - months_paid\n           pending_amount = annual - paid\n\n\n           # only show defaulters\n           if pending_amount > 0:\n               rows.append((\n                   name,\n                   cls,\n                   phone,\n                   int(annual),\n                   int(paid),\n                   months_paid,\n                   pending_months,\n                   int(pending_amount)\n               ))\n\n\n       headers = [\n           \"Student\",\n           \"Class\",\n           \"Phone\",\n           \"Annual Fee\",\n           \"Paid\",\n           \"Months Paid\",\n           \"Pending Months\",\n           \"Pending Amount\"\n       ]\n\n\n       self.table.setRowCount(len(rows))\n       self.table.setColumnCount(len(headers))\n       self.table.setHorizontalHeaderLabels(headers)\n\n\n       for r, row in enumerate(rows):\n           for c, val in enumerate(row):\n               self.table.setItem(r, c, QTableWidgetItem(str(val)))\n\n\n       # self.table.resizeColumnsToContents()\n        style_table(self.table)------------3\n\n       style_table(self.table)\n\n   # -------------------------------------------------\n   def export_excel(self):\n       rows = []\n       for r in range(self.table.rowCount()):\n           row = []\n           for c in range(self.table.columnCount()):\n               row.append(self.table.item(r, c).text())\n           rows.append(row)\n\n\n       self.db.export_excel(rows, \"sms_reminder.xlsx\")\n       QMessageBox.information(self, \"Saved\", \"sms_reminder.xlsx created\")\n\n\n# =================================================\n# DEFAULTER PAGE\n# =================================================\nclass DefaulterPage(QWidget):\n   def __init__(self):\n       super().__init__()\n       self.db = Database()\n\n\n       layout = QVBoxLayout(self)\n\n\n       layout.addWidget(PageHeader(\"Fee Defaulters\"))\n\n\n       self.table = QTableWidget()\n       layout.addWidget(self.table)\n\n\n       self.load_data()\n\n   def style_report_table(self, table):\n       from PySide6.QtWidgets import QHeaderView, QSizePolicy, QAbstractItemView\n\n       table.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)\n\n       header = table.horizontalHeader()\n\n       # Prevent overlapping\n       header.setSectionResizeMode(QHeaderView.Stretch)\n\n       table.verticalHeader().setVisible(False)\n       table.verticalHeader().setDefaultSectionSize(28)\n\n       table.setAlternatingRowColors(True)\n       table.setWordWrap(True)\n       table.setSortingEnabled(True)\n\n       # \u2705 Correct fix\n       table.setEditTriggers(QAbstractItemView.NoEditTriggers)\n\n       header.setMinimumHeight(35)\n   # ---------------------------------------------\n   def load_data(self):\n       from PySide6.QtGui import QColor\n       students = self.db.get_students()\n       vouchers = self.db.get_vouchers()\n\n\n       rows = []\n\n\n       for s in students:\n           sid = s[1]\n           name = s[2]\n           cls = s[7]\n           annual = float(s[13] or 0)\n\n\n           monthly = annual / 12 if annual else 0\n\n\n           paid = sum(\n               float(v[7])\n               for v in vouchers\n               if v[3].lower() == \"fees\" and v[5] == name\n           )\n\n\n           pending = annual - paid\n\n\n           if pending > 0:\n               pending_months = int(pending / monthly) if monthly else 0\n               rows.append((sid, name, cls, int(pending), pending_months))\n\n\n       headers = [\"ID\", \"Name\", \"Class\", \"Pending \u20b9\", \"Pending Months\"]\n\n\n       self.table.setRowCount(len(rows))\n       self.table.setColumnCount(len(headers))\n       self.table.setHorizontalHeaderLabels(headers)\n\n\n       for r, row in enumerate(rows):\n           for c, val in enumerate(row):\n               item = QTableWidgetItem(str(val))\n\n\n               if c >= 3:\n                   item.setForeground(QColor(\"red\"))\n\n\n               self.table.setItem(r, c, item)\n\n\n       # self.table.resizeColumnsToContents()\n        style_table(self.table)-------4\n       style_table(self.table)\n# =================================================\n\n# MONTHLY COLLECTION\n# =================================================\nclass CollectionPage(QWidget):\n   def __init__(self):\n       super().__init__()\n       self.db = Database()\n\n\n       layout = QVBoxLayout(self)\n       layout.addWidget(PageHeader(\"Monthly Collection\"))\n\n\n       self.table = QTableWidget()\n       layout.addWidget(self.table)\n\n\n       self.load_data()\n\n   def style_report_table(self, table):\n       from PySide6.QtWidgets import QHeaderView, QSizePolicy, QAbstractItemView\n\n       table.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)\n\n       header = table.horizontalHeader()\n\n       # Prevent overlapping\n       header.setSectionResizeMode(QHeaderView.Stretch)\n\n       table.verticalHeader().setVisible(False)\n       table.verticalHeader().setDefaultSectionSize(28)\n\n       table.setAlternatingRowColors(True)\n       table.setWordWrap(True)\n       table.setSortingEnabled(True)\n\n       # \u2705 Correct fix\n       table.setEditTriggers(QAbstractItemView.NoEditTriggers)\n\n       header.setMinimumHeight(35)\n   # ---------------------------------------------\n   def load_data(self):\n       rows = self.db.get_vouchers()\n\n\n       monthly = {}\n\n\n       for v in rows:\n           date_str = v[1]\n\n\n           # \u2705 skip invalid dates\n           if not date_str:\n               continue\n\n\n           # safe slicing\n           month = date_str[:7]  # YYYY-MM\n\n\n           amount = float(v[7] or 0)\n\n\n           if v[2] == \"Income\":\n               monthly.setdefault(month, 0)\n               monthly[month] += amount\n\n\n       data = sorted(monthly.items())\n\n\n       self.table.setRowCount(len(data))\n       self.table.setColumnCount(2)\n       self.table.setHorizontalHeaderLabels([\"Month\", \"Collection\"])\n\n\n       for r, (m, total) in enumerate(data):\n           self.table.setItem(r, 0, QTableWidgetItem(m))\n           self.table.setItem(r, 1, QTableWidgetItem(f\"\u20b9{int(total):,}\"))\n           style_table(self.table)\n\n\n# =================================================\n# FEE RECEIPT PDF\n# =================================================\ndef print_fee_receipt(student_name, amount, mode=\"Cash\"):\n\n   filename = f\"fee_receipt_{datetime.now().strftime('%Y%m%d_%H%M%S')}.pdf\"\n\n   doc = SimpleDocTemplate(filename)\n   styles = getSampleStyleSheet()\n   elements = []\n\n\n   elements.append(Paragraph(\"School Fee Receipt\", styles[\"Heading1\"]))\n   elements.append(Spacer(1, 25))\n\n\n   data = [\n       [\"Student\", student_name],\n       [\"Amount\", f\"\u20b9 {amount}\"],\n       [\"Mode\", mode],\n       [\"Date\", datetime.now().strftime(\"%d-%m-%Y\")]\n   ]\n\n\n   table = Table(data)\n   table.setStyle(TableStyle([\n       (\"GRID\", (0, 0), (-1, -1), 1, colors.black),\n       (\"PADDING\", (0, 0), (-1, -1), 8)\n   ]))\n\n\n   elements.append(table)\n\n\n   doc.build(elements)\n\n\n   os.startfile(filename)# =========================================================", "student_list.py": "from ui2.common_table import style_table\n# Student List Page (clean + professional table view)\n# =========================================================\n\nfrom PySide6.QtWidgets import *\nfrom PySide6.QtCore import Qt\nfrom database import Database\nfrom ui2.header import PageHeader\n\n\nclass StudentList(QWidget):\n\n    # =================================================\n    # INIT\n    # =================================================\n    def __init__(self):\n        super().__init__()\n\n        self.db = Database()\n\n        main_layout = QVBoxLayout(self)\n        main_layout.setSpacing(12)\n        main_layout.setContentsMargins(15, 15, 15, 15)\n\n        # =================================================\n        # HEADER\n        # =================================================\n        main_layout.addWidget(PageHeader(\"Student List\"))\n\n        # =================================================\n        # SEARCH BAR\n        # =================================================\n        self.search = QLineEdit()\n        self.search.setPlaceholderText(\"\ud83d\udd0d  Search student...\")\n        self.search.setFixedHeight(34)\n\n        self.search.setStyleSheet(\"\"\"\n            QLineEdit {\n                padding-left:8px;\n                border:1px solid #d0d0d0;\n                border-radius:6px;\n                background:white;\n            }\n        \"\"\")\n\n        main_layout.addWidget(self.search)\n\n        # =================================================\n        # TABLE\n        # =================================================\n        self.table = QTableWidget()\n        self.table.setAlternatingRowColors(True)\n\n        self.table.setAlternatingRowColors(True)\n        self.table.setSelectionBehavior(QTableWidget.SelectRows)\n        self.table.setEditTriggers(QTableWidget.NoEditTriggers)\n        self.table.setShowGrid(True)\n\n        # row height\n        self.table.verticalHeader().setDefaultSectionSize(36)\n\n        # stretch last column\n        self.table.horizontalHeader().setStretchLastSection(True)\n\n        # header style (important for clarity)\n        self.table.horizontalHeader().setStyleSheet(\"\"\"\n            QHeaderView::section {\n                background-color:#E8ECF5;\n                font-weight:bold;\n                padding:6px;\n                border:1px solid #d0d0d0;\n            }\n        \"\"\")\n\n        # table style\n        self.table.setStyleSheet(\"\"\"\n            QTableWidget {\n                background:white;\n                gridline-color:#dcdcdc;\n                alternate-background-color:#F7F9FC;\n            }\n        \"\"\")\n\n        main_layout.addWidget(self.table, 1)\n\n        # =================================================\n        # CONNECTIONS\n        # =================================================\n        self.search.textChanged.connect(self.filter_table)\n\n        # =================================================\n        # LOAD DATA\n        # =================================================\n        self.refresh()\n\n\n    # =================================================\n    # REFRESH TABLE\n    # =================================================\n    def refresh(self):\n        rows = self.db.get_students()\n\n        headers = [\n            \"Name\",\n            \"Father\",\n            \"Phone 1\",\n            \"Phone 2\",\n            \"Location\",\n            \"City\"\n        ]\n\n        self.table.setRowCount(len(rows))\n        self.table.setColumnCount(len(headers))\n        self.table.setHorizontalHeaderLabels(headers)\n\n        for r, row in enumerate(rows):\n            values = [\n                row[2],\n                row[3],\n                row[8],\n                row[9],\n                row[10],\n                row[11]\n            ]\n\n            for c, val in enumerate(values):\n                item = QTableWidgetItem(str(val))\n                item.setTextAlignment(Qt.AlignCenter)\n                self.table.setItem(r, c, item)\n\n        self.table.resizeColumnsToContents()\n        style_table(self.table)\n\n\n    # =================================================\n    # SEARCH FILTER\n    # =================================================\n    def filter_table(self, text):\n        text = text.lower()\n\n        for row in range(self.table.rowCount()):\n            visible = any(\n                text in self.table.item(row, c).text().lower()\n                for c in range(self.table.columnCount())\n                if self.table.item(row, c)\n            )\n            self.table.setRowHidden(row, not visible)", "student_page.py": "from PySide6.QtWidgets import *\nfrom PySide6.QtCore import Qt, Signal\nfrom ui2.student_registration import StudentRegistration\nfrom ui2.student_list import StudentList\n\n\nclass StudentPage(QWidget):\n    student_added = Signal()\n    def __init__(self):\n        super().__init__()\n\n        layout = QVBoxLayout(self)\n\n        # ===== stacked pages ONLY (no buttons needed now) =====\n        self.stack = QStackedWidget()\n\n        self.reg_page = StudentRegistration()\n        self.list_page = StudentList()\n        self.reg_page.student_added.connect(self.student_added.emit)\n\n        self.stack.addWidget(self.reg_page)\n        self.stack.addWidget(self.list_page)\n\n        layout.addWidget(self.stack)\n\n        # =================================================\n        # Default Open\n        # =================================================\n        self.show_registration()\n\n        # =================================================\n        # Required Methods (Mainwindow Calls these)\n        # =================================================\n    def show_registration(self):\n        self.stack.setCurrentWidget(self.reg_page)\n\n    def show_list(self):\n        self.list_page.refresh()  # \u2b50 refresh table first\n        self.stack.setCurrentWidget(self.list_page)", "student_registration.py": "from PySide6.QtWidgets import *\nfrom PySide6.QtCore import Qt, QRegularExpression\nfrom PySide6.QtGui import QRegularExpressionValidator\nfrom database import Database\nfrom ui2.header import PageHeader\nfrom ui2.helpers import setup_combo, mark_invalid, clear_invalid\nfrom datetime import datetime, date\nfrom PySide6.QtCore import Signal\n\nclass StudentRegistration(QWidget):\n    student_added = Signal()  # \u2705 ADD HERE\n    def __init__(self):\n        super().__init__()\n\n        self.db = Database()\n\n        main = QVBoxLayout(self)\n        main.setSpacing(15)\n\n        main.addWidget(PageHeader(\"Student Registration\"))\n\n        # ================= FORM CARD =================\n        card = QFrame()\n        card.setStyleSheet(\"\"\"\n            QFrame {\n                background:white;\n                border-radius:12px;\n                padding:20px;\n            }\n\n            QLabel {\n                font-size:14px;\n            }\n\n            QLineEdit, QComboBox {\n                min-height:34px;\n                font-size:14px;\n                padding:4px;\n            }\n        \"\"\")\n\n        grid = QGridLayout(card)\n        grid.setSpacing(12)\n\n        # ---------- widgets ----------\n        self.student_id = QLineEdit()\n        self.student_id.setReadOnly(True)\n\n        self.name = QLineEdit()\n        self.father = QLineEdit()\n        self.aadhaar = QLineEdit()\n\n        # ---------- dates ----------\n        self.dob = QLineEdit()\n        self.join_date = QLineEdit()\n\n        self.dob.setInputMask(\"00-00-0000;_\")\n        self.join_date.setInputMask(\"00-00-0000;_\")\n\n        self.dob.setPlaceholderText(\"Enter DOB (dd-mm-yyyy)\")\n        self.join_date.setPlaceholderText(\"Enter DOJ (dd-mm-yyyy)\")\n\n        self.dob.textChanged.connect(lambda: clear_invalid(self.dob))\n        self.join_date.textChanged.connect(lambda: clear_invalid(self.join_date))\n\n        self.dob.editingFinished.connect(lambda: self.validate_date_field(self.dob))\n        self.join_date.editingFinished.connect(lambda: self.validate_date_field(self.join_date))\n\n        # ---------- others ----------\n        self.class_combo = QComboBox()\n        setup_combo(self.class_combo, \"Select Class\", [\"6th\", \"7th\", \"8th\", \"9th\", \"10th\"])\n\n        self.phone1 = QLineEdit()\n        self.phone2 = QLineEdit()\n        self.address = QLineEdit()\n        self.location = QLineEdit()\n        self.city = QLineEdit()\n        self.fee = QLineEdit()\n\n        # ---------- validators ----------\n        self.aadhaar.setValidator(QRegularExpressionValidator(QRegularExpression(r\"\\d{12}\")))\n        self.phone1.setValidator(QRegularExpressionValidator(QRegularExpression(r\"\\d{10}\")))\n        self.phone2.setValidator(QRegularExpressionValidator(QRegularExpression(r\"\\d{10}\")))\n\n        self.aadhaar.setPlaceholderText(\"12 digit Aadhaar\")\n        self.phone1.setPlaceholderText(\"10 digit mobile\")\n        self.phone2.setPlaceholderText(\"optional\")\n        self.fee.setPlaceholderText(\"\u20b9 Amount\")\n\n        # ---------- grid ----------\n        fields = [\n            (\"ID\", self.student_id), (\"Name\", self.name),\n            (\"Father Name\", self.father), (\"Aadhaar\", self.aadhaar),\n            (\"DOB\", self.dob), (\"Join Date\", self.join_date),\n            (\"Class\", self.class_combo), (\"Phone-1\", self.phone1),\n            (\"Phone-2\", self.phone2), (\"Address\", self.address),\n            (\"Location\", self.location), (\"City\", self.city),\n            (\"Annual Fee\", self.fee),\n        ]\n\n        for i, (txt, w) in enumerate(fields):\n            grid.addWidget(QLabel(txt), i // 2, (i % 2) * 2)\n            grid.addWidget(w, i // 2, (i % 2) * 2 + 1)\n\n        main.addWidget(card)\n\n        # ================= BUTTONS =================\n        btn_layout = QHBoxLayout()\n\n        self.btn_new = QPushButton(\"\ud83c\udd95 New\")\n        self.btn_save = QPushButton(\"\ud83d\udcbe Save\")\n        self.btn_delete = QPushButton(\"\ud83d\uddd1 Delete\")\n        self.btn_clear = QPushButton(\"\ud83d\udd04 Clear\")\n\n        for b in [self.btn_new, self.btn_save, self.btn_delete, self.btn_clear]:\n            b.setMinimumWidth(120)\n            btn_layout.addWidget(b)\n\n        main.addLayout(btn_layout)\n\n        # ---------- connections ----------\n        self.btn_new.clicked.connect(self.new_student)\n        self.btn_save.clicked.connect(self.save_student)\n        self.btn_delete.clicked.connect(self.delete_student)\n        self.btn_clear.clicked.connect(self.clear_form)\n\n        # ---------- TAB ORDER ----------\n        QWidget.setTabOrder(self.name, self.father)\n        QWidget.setTabOrder(self.father, self.aadhaar)\n        QWidget.setTabOrder(self.aadhaar, self.dob)\n        QWidget.setTabOrder(self.dob, self.join_date)\n        QWidget.setTabOrder(self.join_date, self.class_combo)\n        QWidget.setTabOrder(self.class_combo, self.phone1)\n        QWidget.setTabOrder(self.phone1, self.phone2)\n        QWidget.setTabOrder(self.phone2, self.address)\n        QWidget.setTabOrder(self.address, self.location)\n        QWidget.setTabOrder(self.location, self.city)\n        QWidget.setTabOrder(self.city, self.fee)\n        QWidget.setTabOrder(self.fee, self.btn_save)\n\n        self.btn_save.setDefault(True)\n        self.new_student()\n\n    # ================= FUNCTIONS =================\n\n    def new_student(self):\n        self.clear_form()\n        self.student_id.setText(self.db.next_student_id())\n        self.name.setFocus()\n\n    def save_student(self):\n        if not self.name.text():\n            mark_invalid(self.name)\n            return\n\n        data = (\n            self.student_id.text(),\n            self.name.text(),\n            self.father.text(),\n            self.aadhaar.text(),\n            self.dob.text(),\n            self.join_date.text(),\n            self.class_combo.currentText(),\n            self.phone1.text(),\n            self.phone2.text(),\n            self.location.text(),\n            self.city.text(),\n            self.address.text(),\n            float(self.fee.text() or 0)\n        )\n\n        self.db.add_student(data)\n        # self.parent().voucher_page.load_students()\n        # self.parent().report_page.load_students()\n        self.student_added.emit()  # \ud83d\udd25 THIS ONLY\n        QMessageBox.information(self, \"Saved\", \"Student saved\")\n        self.new_student()\n\n    def delete_student(self):\n        self.db.delete_student(self.student_id.text())\n        self.new_student()\n\n    def clear_form(self):\n        for w in [\n            self.name, self.father, self.aadhaar, self.phone1,\n            self.phone2, self.location, self.city, self.address,\n            self.fee, self.dob, self.join_date\n        ]:\n            w.clear()\n\n        self.class_combo.setCurrentIndex(0)\n\n    # ---------- DATE VALIDATION ----------\n    def validate_date_field(self, widget):\n        text = widget.text().strip()\n\n        if not text:\n            mark_invalid(widget)\n            return\n\n        try:\n            entered = datetime.strptime(text, \"%d-%m-%Y\").date()\n            if entered > date.today():\n                raise ValueError\n            clear_invalid(widget)\n        except ValueError:   # \u2b50 FIXED HERE\n            mark_invalid(widget)", "voucher_actions.py": "import os\nfrom datetime import datetime\nfrom reportlab.pdfgen import canvas\nfrom reportlab.lib.pagesizes import inch\nfrom PyPDF2 import PdfReader, PdfWriter\nfrom reportlab.pdfbase.ttfonts import TTFont\nfrom reportlab.pdfbase import pdfmetrics\nfont_path = r\"D:\\Newapp\\fonts\\DejaVuSans.ttf\"\npdfmetrics.registerFont(TTFont(\"DejaVu\", font_path))\nbold_font_path = r\"D:\\Newapp\\fonts\\DejaVuSans-Bold.ttf\"\npdfmetrics.registerFont(TTFont(\"DejaVuBold\", bold_font_path))\n# ================= Amount to Words =================\ndef number_to_words(n):\n\n    n = int(float(n))\n\n    if n == 0:\n        return \"Zero Rupees Only\"\n\n    ones = [\"\",\"One\",\"Two\",\"Three\",\"Four\",\"Five\",\"Six\",\"Seven\",\"Eight\",\"Nine\",\n            \"Ten\",\"Eleven\",\"Twelve\",\"Thirteen\",\"Fourteen\",\"Fifteen\",\"Sixteen\",\n            \"Seventeen\",\"Eighteen\",\"Nineteen\"]\n\n    tens = [\"\",\"\",\"Twenty\",\"Thirty\",\"Forty\",\"Fifty\",\"Sixty\",\"Seventy\",\"Eighty\",\"Ninety\"]\n\n    def words(num):\n        if num < 20:\n            return ones[num]\n        elif num < 100:\n            return (tens[num//10] + (\" \" + ones[num%10] if num%10 else \"\")).strip()\n        elif num < 1000:\n            return (ones[num//100] + \" Hundred\" +\n                    (\" \" + words(num%100) if num%100 else \"\")).strip()\n        elif num < 100000:\n            return (words(num//1000) + \" Thousand\" +\n                    (\" \" + words(num%1000) if num%1000 else \"\")).strip()\n        else:\n            return str(num)\n\n    return words(n) + \" Rupees Only\"\n\n\n# ================= Generate Receipt On Template =================\ndef generate_fee_receipt(voucher_no, student, cls, breakdown, amount, mode, note):\n\n    # ---------------- TEMPLATE PATH ----------------\n    template_path = r\"D:\\Newapp\\assets\\R1.pdf\"\n    output_path = os.path.join(os.getcwd(), f\"fee_receipt_{voucher_no}.pdf\")\n\n    # ---------------- TEMP OVERLAY FILE ----------------\n    overlay_path = \"temp_overlay.pdf\"\n\n    # 8.27 X 5.83 size in points (1 inch = 72 points)\n    width = 8.27 * inch\n    height = 5.83 * inch\n\n    c = canvas.Canvas(overlay_path, pagesize=(width, height))\n\n    # Labels Bold\n    c.setFont(\"DejaVuBold\", 10)\n    label_x = 50\n    colon_x = 120  # fixed colon position\n    x = 135  # value starts after colon\n\n    c.setFont(\"DejaVuBold\", 10)\n\n    fields = [\n        (\"Receipt No\", 300),\n        (\"Student\", 270),\n        (\"Class\", 240),\n        (\"Amount\", 210),\n        (\"In Words\", 180),\n        (\"Mode\", 150),\n        (\"Note\", 120),\n        (\"Paid Upto\", 90),\n\n    ]\n    for text, y in fields:\n        c.drawString(label_x, y, text)\n        c.drawString(colon_x, y, \":\")\n\n    # Values Normal\n    c.setFont(\"DejaVu\", 10)\n    c.drawString(x, 300, f\"{voucher_no}\")\n    c.drawString(500, 300, f\"{datetime.now().strftime('%d-%m-%Y')}\")\n\n    c.drawString(x, 270, student)\n    c.drawString(x, 240, cls)\n    # ----- EMI Range Display -----\n    if breakdown:\n        start_month = breakdown[0][0]\n        end_month = breakdown[-1][0]\n\n        if start_month == end_month:\n            months_text = start_month\n        else:\n            months_text = f\"{start_month} - {end_month}\"\n    else:\n        months_text = \"-\"\n\n    c.drawString(x, 210, f\"\u20b9 {int(amount):,}/-\")\n    c.drawString(x, 180, number_to_words(amount))\n    c.drawString(x, 150, mode)\n    c.drawString(x, 120, note)\n    c.drawString(x, 90, months_text)\n    # Signature Bold\n    c.setFont(\"DejaVuBold\", 10)\n    c.drawString(350, 90, \"Authorized Signature\")\n    c.drawString(450, 300, \"Date :\")\n    c.save()\n\n    # ---------------- MERGE WITH TEMPLATE ----------------\n    template_pdf = PdfReader(template_path)\n    overlay_pdf = PdfReader(overlay_path)\n\n    writer = PdfWriter()\n\n    base_page = template_pdf.pages[0]\n    base_page.merge_page(overlay_pdf.pages[0])\n\n    writer.add_page(base_page)\n\n    with open(output_path, \"wb\") as f:\n        writer.write(f)\n\n    os.remove(overlay_path)\n\n    os.startfile(output_path)", "vouchers.py": "from ui2.common_table import style_table\nfrom PySide6.QtWidgets import (\n    QWidget, QVBoxLayout, QFormLayout, QDateEdit, QComboBox, QLabel,\n    QLineEdit, QPushButton, QHBoxLayout, QTableWidget, QTableWidgetItem,\n    QMessageBox, QApplication, QHeaderView, QSizePolicy, QAbstractItemView\n)\nfrom backend import Backend\nfrom PySide6.QtCore import QDate, Qt\nfrom database import Database\nfrom ui2.header import PageHeader\nfrom .voucher_actions import generate_fee_receipt\nimport sys\n\n\n\n\n# ======================================================\n# VOUCHER PAGE\n# ======================================================\nclass VoucherPage(QWidget):\n    def __init__(self):\n        super().__init__()\n        self.db = Database()\n        self.backend = Backend()\n        layout = QVBoxLayout(self)\n        layout.addWidget(PageHeader(\"Voucher Entry\"))\n\n        form = QFormLayout()\n\n        self.date = QDateEdit(QDate.currentDate(), calendarPopup=True)\n        self.date.setDisplayFormat(\"dd/MM/yyyy\")\n        self.type_combo = QComboBox()\n        self.type_combo.addItems([\"Select Income/Expense\", \"Income\", \"Expense\"])\n\n        self.head = QComboBox()\n        self.head.addItem(\"Select Head\")\n\n        self.subhead = QComboBox()\n        self.subhead.addItem(\"Select Sub Head\")\n\n        self.student_lbl = QLabel(\"Student\")\n        self.student_combo = QComboBox()\n        self.student_combo.addItem(\"Select Student\")\n\n        self.class_lbl = QLabel(\"Class\")\n        self.class_edit = QLineEdit()\n        self.class_edit.setReadOnly(True)\n\n        self.amount = QLineEdit()\n\n        self.mode = QComboBox()\n        self.mode.addItems([\"Select Mode\", \"Cash\", \"Bank\", \"UPI\", \"PhonePe\", \"GooglePay\"])\n\n        self.note = QLineEdit()\n\n        form.addRow(\"Date\", self.date)\n        form.addRow(\"Type\", self.type_combo)\n        form.addRow(\"Head\", self.head)\n        form.addRow(\"Subhead\", self.subhead)\n        form.addRow(self.student_lbl, self.student_combo)\n        form.addRow(self.class_lbl, self.class_edit)\n        form.addRow(\"Amount\", self.amount)\n        form.addRow(\"Mode\", self.mode)\n        form.addRow(\"Note\", self.note)\n\n        layout.addLayout(form)\n\n        btn_row = QHBoxLayout()\n        btn_save = QPushButton(\"Save\")\n        btn_print = QPushButton(\"Print\")\n        btn_new = QPushButton(\"New\")\n\n        btn_row.addWidget(btn_save)\n        btn_row.addWidget(btn_print)\n        btn_row.addWidget(btn_new)\n        layout.addLayout(btn_row)\n\n        self.table = QTableWidget()\n        headers = [\"Voucher No\", \"Date\", \"Type\", \"Head\", \"Sub\", \"Name\",\n                   \"Class\", \"Amount\", \"Mode\", \"Description\"]\n        self.table.setColumnCount(len(headers))\n        self.table.setHorizontalHeaderLabels(headers)\n        layout.addWidget(self.table)\n\n        style_table(self.table)\n\n        # Connections\n        btn_save.clicked.connect(self.save_voucher)\n        btn_print.clicked.connect(self.print_receipt)\n        btn_new.clicked.connect(self.clear_form)\n        self.type_combo.currentTextChanged.connect(self.load_heads)\n        self.head.currentTextChanged.connect(self.load_subheads)\n        self.student_combo.currentIndexChanged.connect(self.load_student_class)\n\n        # Hide student section initially\n        self.student_lbl.setVisible(False)\n        self.student_combo.setVisible(False)\n        self.class_lbl.setVisible(False)\n        self.class_edit.setVisible(False)\n\n        self.load_students()\n        self.refresh()\n\n    # =================================================\n    def style_report_table(self, table):\n        table.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)\n        header = table.horizontalHeader()\n        header.setSectionResizeMode(QHeaderView.Stretch)\n        table.verticalHeader().setVisible(False)\n        table.setAlternatingRowColors(True)\n        table.setSortingEnabled(True)\n        table.setEditTriggers(QAbstractItemView.NoEditTriggers)\n\n    # =================================================\n    def load_students(self):\n        self.student_combo.clear()\n        self.student_combo.addItem(\"Select Student\", None)\n\n        students = self.db.get_students()\n\n        for s in students:\n            # Based on your table structure\n            # s[0] = id (auto id)\n            # s[1] = student_id\n            # s[2] = name\n            # s[7] = class\n            self.student_combo.addItem(\n                f\"{s[2]} ({s[1]})\",  # Show name + student_id\n                s\n            )\n    # =================================================\n    def load_heads(self):\n        self.head.clear()\n        self.head.addItem(\"Select Head\")\n        self.subhead.clear()\n        self.subhead.addItem(\"Select Sub Head\")\n        self.head.addItems(self.db.get_heads(self.type_combo.currentText()))\n\n    # =================================================\n    def load_subheads(self):\n        self.subhead.clear()\n        self.subhead.addItem(\"Select Sub Head\")\n        self.subhead.addItems(\n            self.db.get_subheads(self.type_combo.currentText(), self.head.currentText())\n        )\n\n        if self.head.currentText().lower() == \"fees\":\n            self.student_lbl.setVisible(True)\n            self.student_combo.setVisible(True)\n            self.class_lbl.setVisible(True)\n            self.class_edit.setVisible(True)\n        else:\n            self.student_lbl.setVisible(False)\n            self.student_combo.setVisible(False)\n            self.class_lbl.setVisible(False)\n            self.class_edit.setVisible(False)\n            self.student_combo.setCurrentIndex(0)\n            self.class_edit.clear()\n\n    # =================================================\n    def load_student_class(self):\n        student = self.student_combo.currentData()\n\n        if student:\n            self.class_edit.setText(student[7])\n        else:\n            self.class_edit.clear()\n\n    # =================================================\n    def save_voucher(self):\n\n        if self.type_combo.currentIndex() == 0:\n            QMessageBox.warning(self, \"Error\", \"Select Type\")\n            return\n\n        if self.head.currentIndex() == 0:\n            QMessageBox.warning(self, \"Error\", \"Select Head\")\n            return\n\n        if self.subhead.currentIndex() == 0:\n            QMessageBox.warning(self, \"Error\", \"Select Subhead\")\n            return\n\n        if self.head.currentText().lower() == \"fees\":\n            if self.student_combo.currentIndex() == 0:\n                QMessageBox.warning(self, \"Error\", \"Select Student\")\n                return\n\n        try:\n            amount = float(self.amount.text())\n            if amount <= 0:\n                raise ValueError\n        except:\n            QMessageBox.warning(self, \"Error\", \"Enter valid amount\")\n            return\n\n        if self.mode.currentIndex() == 0:\n            QMessageBox.warning(self, \"Error\", \"Select Mode\")\n            return\n        student = self.student_combo.currentData() or (\"\", \"\", \"\", \"\", \"\", \"\", \"\", \"\")\n\n        voucher_data = (\n            self.date.date().toString(\"yyyy-MM-dd\"),\n            self.type_combo.currentText(),\n            self.head.currentText(),\n            self.subhead.currentText(),\n            student[2] if student else \"\",  # student name\n            student[7] if student else \"\",  # class\n            amount,\n            self.mode.currentText(),\n            self.note.text()\n        )\n        self.db.add_voucher(voucher_data)\n        QMessageBox.information(self, \"Saved\", \"Voucher Saved Successfully\")\n        self.refresh()\n        self.load_students()\n        self.load_heads()\n        self.load_subheads()\n        self.clear_form()\n\n    # =================================================\n\n\n    def print_receipt(self):\n        row = self.table.currentRow()\n\n        if row < 0:\n            QMessageBox.warning(self, \"Error\", \"Select voucher from table\")\n            return\n\n        head = self.table.item(row, 3).text()\n\n        if \"fee\" not in head.lower():\n            QMessageBox.warning(self, \"Error\", \"Receipt only for Fees\")\n            return\n\n        voucher_no = self.table.item(row, 0).text()\n        student = self.table.item(row, 5).text()\n        cls = self.table.item(row, 6).text()\n\n        item = self.table.item(row, 7)\n\n        if not item:\n            QMessageBox.warning(self, \"Error\", \"Amount not found\")\n            return\n\n        text = item.text()\n        clean = text.replace(\"\u20b9\", \"\").replace(\",\", \"\").replace(\"/-\", \"\").strip()\n\n        try:\n            amount = float(clean)\n        except ValueError:\n            QMessageBox.warning(self, \"Error\", \"Invalid amount format\")\n            return\n\n        mode = self.table.item(row, 8).text()\n        note = self.table.item(row, 9).text()\n\n        # \u2705 EMI BREAKDOWN\n        breakdown = self.backend.calculate_emi_breakdown(student, amount)\n\n        # Send breakdown instead of single month\n        generate_fee_receipt(voucher_no, student, cls, breakdown,  amount, mode, note) # \ud83d\udd25 changed\n\n    # =================================================\n    def clear_form(self):\n        self.type_combo.setCurrentIndex(0)\n        self.head.clear()\n        self.head.addItem(\"Select Head\")\n        self.subhead.clear()\n        self.subhead.addItem(\"Select Sub Head\")\n        self.student_combo.setCurrentIndex(0)\n        self.class_edit.clear()\n        self.amount.clear()\n        self.mode.setCurrentIndex(0)\n        self.note.clear()\n        self.student_lbl.setVisible(False)\n        self.student_combo.setVisible(False)\n        self.class_lbl.setVisible(False)\n        self.class_edit.setVisible(False)\n\n    def refresh(self):\n\n        rows = self.db.get_vouchers()\n        self.table.setRowCount(len(rows))\n\n        for r, row in enumerate(rows):\n            for c, val in enumerate(row):\n                # -------- Format Date Column --------\n                if c == 1 and val:\n                    try:\n                        date_obj = QDate.fromString(val, \"yyyy-MM-dd\")\n                        formatted = date_obj.toString(\"dd/MM/yyyy\")\n                        item = QTableWidgetItem(formatted)\n                    except:\n                        item = QTableWidgetItem(str(val))\n\n                # Format Amount column (index 7)\n                elif c == 7 and val is not None:\n                    try:\n                        formatted = f\"\u20b9 {int(float(val)):,}/-\"\n                        item = QTableWidgetItem(formatted)\n                        item.setTextAlignment(Qt.AlignRight | Qt.AlignVCenter)\n                    except:\n                        item = QTableWidgetItem(str(val))\n                else:\n                    item = QTableWidgetItem(str(val))\n\n                self.table.setItem(r, c, item)\n        style_table(self.table)\n# ======================================================\nif __name__ == \"__main__\":\n    app = QApplication(sys.argv)\n    window = VoucherPage()\n    window.resize(1000, 600)\n    window.show()\n    sys.exit(app.exec())", "common_table.py": "from PySide6.QtWidgets import QHeaderView, QAbstractItemView\nfrom PySide6.QtCore import Qt\n\ndef style_table(table):\n    header = table.horizontalHeader()\n    header.setSectionResizeMode(QHeaderView.Stretch)\n    header.setStyleSheet(\"QHeaderView::section { font-weight:bold; padding:6px; }\")\n    table.verticalHeader().setVisible(False)\n    table.setAlternatingRowColors(True)\n    table.setSortingEnabled(True)\n    table.setEditTriggers(QAbstractItemView.NoEditTriggers)\n    # center all existing items\n    for r in range(table.rowCount()):\n        for c in range(table.columnCount()):\n            it = table.item(r,c)\n            if it:\n                it.setTextAlignment(Qt.AlignCenter)"}

def main():
    for path, content in FILES.items():
        p = pathlib.Path(TARGET) / path
        p.parent.mkdir(parents=True, exist_ok=True)
        with open(p, "w", encoding="utf-8") as f:
            f.write(content)
    print("ui2 unpacked to", TARGET)

if __name__ == "__main__":
    main()
